# Create directories if they don't exist
os.makedirs("data/gemini-3-pro-preview/agent_files", exist_ok=True)

try:
    # Use PauliString to ensure correct parsing
    paulis = [stim.PauliString(s) for s in target_stabilizers]
    tableau = stim.Tableau.from_stabilizers(paulis, allow_redundant=True, allow_underconstrained=True)
    circuit = tableau.to_circuit(method="graph_state")
    
    with open("data/gemini-3-pro-preview/agent_files/candidate_graph_state.stim", "w") as f:
        f.write(str(circuit))
    print("Synthesized circuit saved to candidate_graph_state.stim")
    
except Exception as e:
    print(f"Synthesis failed: {e}")
